import{_ as s,a,a3 as t,o as n}from"./chunks/framework.edeurCMZ.js";const h=JSON.parse('{"title":"Configuration File Processor","description":"","frontmatter":{},"headers":[],"relativePath":"tools/roxie/CONFIG_PROCESSOR_README.md","filePath":"tools/roxie/CONFIG_PROCESSOR_README.md","lastUpdated":1782747484000}'),i={name:"tools/roxie/CONFIG_PROCESSOR_README.md"};function o(l,e,r,p,c,d){return n(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="configuration-file-processor" tabindex="-1">Configuration File Processor <a class="header-anchor" href="#configuration-file-processor" aria-label="Permalink to &quot;Configuration File Processor&quot;">​</a></h1><p>This Python script processes configuration files with multiple sections and applies environment variable replacements to XML files. It supports automated deployment to remote machines, test execution with timing analysis, and event tracing.</p><h2 id="configuration-file-format" tabindex="-1">Configuration File Format <a class="header-anchor" href="#configuration-file-format" aria-label="Permalink to &quot;Configuration File Format&quot;">​</a></h2><p>Configuration files support multiple sections and can include other configuration files using <code>@filename</code> syntax.</p><h3 id="file-inclusion" tabindex="-1">File Inclusion <a class="header-anchor" href="#file-inclusion" aria-label="Permalink to &quot;File Inclusion&quot;">​</a></h3><p>Include other configuration files by adding lines starting with <code>@</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@common.config</span></span>
<span class="line"><span>@settings/defaults.config</span></span></code></pre></div><p><strong>Important</strong>: Include files are processed <strong>immediately</strong> when encountered, so order matters. This allows you to:</p><ol><li>Include a file with default values at the top</li><li>Override specific values later in the current file</li></ol><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Load defaults first</span></span>
<span class="line"><span>@defaults.config</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[config]</span></span>
<span class="line"><span># Override specific defaults</span></span>
<span class="line"><span>ROXIE_PORT=9999</span></span></code></pre></div><p>Relative paths are resolved relative to the including file&#39;s directory. Sections from included files are merged with sections in the current file, with later definitions taking precedence.</p><h3 id="config" tabindex="-1">[config] <a class="header-anchor" href="#config" aria-label="Permalink to &quot;[config]&quot;">​</a></h3><p>Contains name=value assignments for configuration variables. These values override system environment variables but can be overridden by command-line arguments.</p><p>Supported variables:</p><ul><li><code>ROXIE_IPS</code> - Comma-separated list of Roxie node IP addresses</li><li><code>SUBMIT_IP</code> - IP address used to submit queries to Roxie</li><li><code>ROXIE_PORT</code> - Port number associated with Roxies</li><li><code>INPUT</code> - Input XML file path (overrides default if --input-xml not specified)</li><li><code>TESTFILE</code> - Test file to pass to testsocket with -ff option</li><li><code>LOCALROOT</code> - Prefix for local paths (e.g., testsocket location). Default: empty</li><li><code>REMOTEROOT</code> - Prefix for remote paths (e.g., /etc/init.d, environment.xml). Default: empty</li><li><code>RESULTS</code> - Base directory for test results (default: <code>results</code>)</li></ul><p>Path construction:</p><ul><li>testsocket: <code>$LOCALROOT/opt/HPCCSystems/bin/testsocket</code></li><li>init.d: <code>$REMOTEROOT/etc/init.d</code></li><li>environment.xml: <code>$REMOTEROOT/etc/HPCCSystems/environment.xml</code></li></ul><h3 id="environment" tabindex="-1">[environment] <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;[environment]&quot;">​</a></h3><p>Contains replacements to be applied to the XML file. Supports two formats:</p><ul><li><code>name=value</code> - Creates XML attribute pattern replacements</li><li><code>pattern --&gt; replacement</code> - Direct regex pattern/replacement pairs</li></ul><h3 id="prepare" tabindex="-1">[prepare] <a class="header-anchor" href="#prepare" aria-label="Permalink to &quot;[prepare]&quot;">​</a></h3><p>Contains a list of commands, one per line. These commands will be executed on each remote node after copying the environment file but before starting HPCC services.</p><h3 id="options" tabindex="-1">[options] <a class="header-anchor" href="#options" aria-label="Permalink to &quot;[options]&quot;">​</a></h3><p>Contains name=value assignments for additional options.</p><p>Supported options:</p><ul><li><code>eventTrace</code> - Set to 1 to enable event recording during tests (default: 0)</li><li><code>copyEvents</code> - Set to 1 to copy event trace files from remote machines (default: 0)</li></ul><h3 id="tests" tabindex="-1">[tests] <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;[tests]&quot;">​</a></h3><p>Contains test definitions in the format &quot;name: options&quot;. Each test will be executed after successful deployment using testsocket. Test options are passed directly to testsocket.</p><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>basic: --timeout=30</span></span>
<span class="line"><span>extreme: --load=high --duration=60</span></span></code></pre></div><h3 id="comments" tabindex="-1">Comments <a class="header-anchor" href="#comments" aria-label="Permalink to &quot;Comments&quot;">​</a></h3><p>Lines starting with <code>#</code> are treated as comments and ignored.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config_processor.py</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">config_fil</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [options]</span></span></code></pre></div><h3 id="required-arguments" tabindex="-1">Required Arguments <a class="header-anchor" href="#required-arguments" aria-label="Permalink to &quot;Required Arguments&quot;">​</a></h3><ul><li><code>config_file</code> - Path to the configuration file to process</li></ul><h3 id="optional-arguments" tabindex="-1">Optional Arguments <a class="header-anchor" href="#optional-arguments" aria-label="Permalink to &quot;Optional Arguments&quot;">​</a></h3><ul><li><code>--input-xml &lt;path&gt;</code> - Path to the XML file to modify</li><li><code>--roxie-ips &lt;ips&gt;</code> - Comma-separated list of Roxie node IP addresses (overrides [config])</li><li><code>--submit-ip &lt;ip&gt;</code> - IP address for query submission (overrides [config])</li><li><code>--roxie-port &lt;port&gt;</code> - Roxie port number (overrides [config])</li><li><code>--dry-run</code> - Preview changes without modifying files or executing commands</li><li><code>--copy-events</code> - Copy event trace files from remote machines to local results directory</li></ul><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><p>Basic usage with a configuration file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config_processor.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-config.txt</span></span></code></pre></div><p>Override configuration with command-line arguments:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config_processor.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-config.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --roxie-ips</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 10.0.0.1,10.0.0.2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --submit-ip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10.0.0.1</span></span></code></pre></div><p>Preview changes without applying them:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config_processor.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-config.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span></code></pre></div><p>Run tests with event tracing and copy event files:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config_processor.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test-config.txt</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --copy-events</span></span></code></pre></div><h2 id="test-execution-and-results" tabindex="-1">Test Execution and Results <a class="header-anchor" href="#test-execution-and-results" aria-label="Permalink to &quot;Test Execution and Results&quot;">​</a></h2><p>When tests are defined in the [tests] section, the script will:</p><ol><li><strong>Deploy Configuration</strong>: Copy modified environment.xml and execute [prepare] commands on remote nodes</li><li><strong>Create Results Directory</strong>: <code>$RESULTS/{testname}/{timestamp}/</code> for each test</li><li><strong>Generate summary.txt</strong>: Records all configuration values, test parameters, and metadata before execution</li><li><strong>Execute Test</strong>: Run testsocket with specified options</li><li><strong>Capture Results</strong>: Save results.xml from testsocket output</li><li><strong>Extract Statistics</strong>: Parse <code>&lt;SummaryStats&gt;</code> XML and save to stats.txt</li><li><strong>Process Timings</strong>: Run extract-roxie-timings.py to generate stats-summary.csv</li><li><strong>Copy Events</strong> (if --copy-events): Copy trace files from remote machines</li><li><strong>Generate CSV Summary</strong>: Create statssummary.csv with configuration and statistics</li></ol><h3 id="results-directory-structure" tabindex="-1">Results Directory Structure <a class="header-anchor" href="#results-directory-structure" aria-label="Permalink to &quot;Results Directory Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>results/</span></span>
<span class="line"><span>  {testname}/</span></span>
<span class="line"><span>    {timestamp}/</span></span>
<span class="line"><span>      summary.txt           # Complete configuration and test metadata</span></span>
<span class="line"><span>      results.xml           # Full testsocket output</span></span>
<span class="line"><span>      stats.txt            # Extracted \`&lt;SummaryStats&gt;\` XML</span></span>
<span class="line"><span>      stats-summary.csv    # Processed timing statistics</span></span>
<span class="line"><span>      statssummary.csv     # Combined configuration and statistics</span></span>
<span class="line"><span>      events/              # Event trace files (if --copy-events used)</span></span>
<span class="line"><span>        {hostname}-{pid}.json</span></span></code></pre></div><h3 id="summary-txt-format" tabindex="-1">summary.txt Format <a class="header-anchor" href="#summary-txt-format" aria-label="Permalink to &quot;summary.txt Format&quot;">​</a></h3><p>The summary.txt file contains:</p><ul><li><strong>[config]</strong> section with all configuration values (including defaults)</li><li><strong>[environment]</strong> section with XML replacement patterns</li><li><strong>[prepare]</strong> section with deployment commands</li><li><strong>[options]</strong> section with runtime options</li><li><strong>timestamp</strong> - ISO 8601 timestamp when test was started</li><li><strong>testsocket_command</strong> - Full command line executed</li><li><strong>event_files</strong> - List of event trace files (if event tracing enabled)</li></ul><h3 id="statistics-extraction" tabindex="-1">Statistics Extraction <a class="header-anchor" href="#statistics-extraction" aria-label="Permalink to &quot;Statistics Extraction&quot;">​</a></h3><p>If extract-roxie-timings.py is present in the same directory, the script will:</p><ol><li>Extract all <code>&lt;SummaryStats&gt;</code> tags from results.xml and save to stats.txt</li><li>Run extract-roxie-timings.py on stats.txt to generate stats-summary.csv</li><li>Merge statistics into statssummary.csv alongside configuration values</li></ol><p>The statssummary.csv contains:</p><ul><li>All [config] values as columns</li><li>All statistics from stats-summary.csv (mean times, counts, etc.)</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li>Parse specified configuration file(s), processing @include directives recursively</li><li>Merge configuration sections from included files with main configuration</li><li>Determine configuration values using precedence: CLI args &gt; config file &gt; environment</li><li>Apply XML replacements from [environment] section to input XML file</li><li>Deploy configuration to remote machines: <ul><li>Stop HPCC services on all Roxie nodes</li><li>Copy modified environment.xml to each node</li><li>Execute [prepare] commands on each node</li><li>Start HPCC services on all nodes</li></ul></li><li>Execute tests from [tests] section: <ul><li>Create timestamped results directory for each test</li><li>Generate summary.txt with complete configuration</li><li>Run testsocket with specified options</li><li>Capture and process results</li><li>Extract statistics and generate CSV summaries</li><li>Copy event trace files if requested</li></ul></li></ol><p><strong>Note</strong>: Deployment requires SSH keys configured for passwordless authentication. If no [environment] replacements are defined, deployment is skipped automatically.</p><h2 id="configuration-precedence" tabindex="-1">Configuration Precedence <a class="header-anchor" href="#configuration-precedence" aria-label="Permalink to &quot;Configuration Precedence&quot;">​</a></h2><p>Configuration values are resolved in the following order (highest priority first):</p><ol><li><strong>Command-line arguments</strong> (--roxie-ips, --submit-ip, --roxie-port)</li><li><strong>[config] section</strong> in the specified config file (including values from @included files)</li><li><strong>System environment variables</strong></li></ol><h3 id="precedence-example" tabindex="-1">Precedence Example <a class="header-anchor" href="#precedence-example" aria-label="Permalink to &quot;Precedence Example&quot;">​</a></h3><p>Given:</p><ul><li>System environment: <code>ROXIE_IPS=192.168.0.1,192.168.0.2</code></li><li>Config file <code>[config]</code>: <code>ROXIE_IPS=192.168.2.10,192.168.2.11</code></li><li>Command line: <code>--roxie-ips=10.0.0.1,10.0.0.2</code></li></ul><p>The final value will be: <code>10.0.0.1,10.0.0.2</code> (command line wins)</p><p><strong>Note</strong>: When using @include files, later definitions override earlier ones within the same configuration file processing.</p><h2 id="dry-run-mode" tabindex="-1">Dry-Run Mode <a class="header-anchor" href="#dry-run-mode" aria-label="Permalink to &quot;Dry-Run Mode&quot;">​</a></h2><p>Use <code>--dry-run</code> to preview what would be executed without actually running commands or modifying files:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config_processor.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sample_config.txt</span></span></code></pre></div><p>In dry-run mode:</p><ul><li>XML replacements are still shown</li><li>SSH/SCP commands are displayed but not executed</li><li>Test commands are shown but not run</li><li>Results directories are still created for structure verification</li><li>Summary files are still written for preview</li></ul><h2 id="sample-configuration-file" tabindex="-1">Sample Configuration File <a class="header-anchor" href="#sample-configuration-file" aria-label="Permalink to &quot;Sample Configuration File&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Configuration file with comments</span></span>
<span class="line"><span>@common-settings.config   # Include shared settings</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[config]</span></span>
<span class="line"><span>ROXIE_IPS=192.168.1.10,192.168.1.11,192.168.1.12</span></span>
<span class="line"><span>SUBMIT_IP=192.168.1.10</span></span>
<span class="line"><span>ROXIE_PORT=9876</span></span>
<span class="line"><span>LOCALROOT=/usr/local</span></span>
<span class="line"><span>REMOTEROOT=/opt/hpcc</span></span>
<span class="line"><span>RESULTS=my_test_results</span></span>
<span class="line"><span>TESTFILE=queries.txt</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[environment]</span></span>
<span class="line"><span># Simple attribute replacements</span></span>
<span class="line"><span>TEST_VAR=sample_value</span></span>
<span class="line"><span>OLD_VALUE=new_value</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Regex pattern replacements</span></span>
<span class="line"><span>old_server_name --&gt; new_server_name</span></span>
<span class="line"><span>192\\.168\\.0\\.\\d+ --&gt; 10.0.0.1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[prepare]</span></span>
<span class="line"><span># Commands to run after deploying environment.xml</span></span>
<span class="line"><span>start_roxie_cluster</span></span>
<span class="line"><span>check_cluster_health</span></span>
<span class="line"><span>deploy_queries</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[options]</span></span>
<span class="line"><span>eventTrace=1</span></span>
<span class="line"><span>copyEvents=1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[tests]</span></span>
<span class="line"><span>basic_test: --timeout=30</span></span>
<span class="line"><span>performance_test: --timeout=60 --load=high</span></span>
<span class="line"><span>smoke_test: --quick</span></span></code></pre></div><p>Note: The [environment] section supports two formats:</p><ul><li><code>name=value</code> - Creates XML attribute pattern replacements</li><li><code>pattern --&gt; replacement</code> - Direct regex pattern/replacement pairs</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Python 3.x</li><li><code>extract-roxie-timings.py</code> (optional, for statistics processing) - must be in same directory as config_processor.py</li><li>SSH access to remote Roxie nodes with passwordless key-based authentication</li><li>testsocket executable (part of HPCC Systems installation)</li></ul><h2 id="advanced-features" tabindex="-1">Advanced Features <a class="header-anchor" href="#advanced-features" aria-label="Permalink to &quot;Advanced Features&quot;">​</a></h2><h3 id="include-files" tabindex="-1">Include Files <a class="header-anchor" href="#include-files" aria-label="Permalink to &quot;Include Files&quot;">​</a></h3><p>Use <code>@filename</code> to include other configuration files. This allows modular configuration management:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># main-config.txt</span></span>
<span class="line"><span>@common/defaults.config</span></span>
<span class="line"><span>@environment/production.config</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[tests]</span></span>
<span class="line"><span>prod_test: --timeout=60</span></span></code></pre></div><p>Included files are processed recursively, and sections are merged. Later definitions override earlier ones within the same section.</p><h3 id="event-tracing" tabindex="-1">Event Tracing <a class="header-anchor" href="#event-tracing" aria-label="Permalink to &quot;Event Tracing&quot;">​</a></h3><p>Enable event tracing to record detailed execution information:</p><ol><li>Set <code>eventTrace=1</code> in [options] section or testing.defaults</li><li>Events are recorded to <code>/var/log/HPCCSystems/myesp/trace_{timestamp}_{pid}.json</code> on each Roxie node</li><li>Use <code>--copy-events</code> or set <code>copyEvents=1</code> in [options] to automatically copy trace files to results directory</li></ol><p>Event files are listed in summary.txt and copied to <code>results/{testname}/{timestamp}/events/</code>.</p><h3 id="path-customization" tabindex="-1">Path Customization <a class="header-anchor" href="#path-customization" aria-label="Permalink to &quot;Path Customization&quot;">​</a></h3><p>Use LOCALROOT and REMOTEROOT to adapt to different deployment environments:</p><ul><li><strong>LOCALROOT</strong>: Prefix for local paths (where testsocket is installed locally)</li><li><strong>REMOTEROOT</strong>: Prefix for remote paths (where services and configs are on remote machines)</li></ul><p>Example for containerized environments:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[config]</span></span>
<span class="line"><span>LOCALROOT=/opt/mycompany</span></span>
<span class="line"><span>REMOTEROOT=/data/hpcc</span></span></code></pre></div><p>This changes paths to:</p><ul><li>testsocket: <code>/opt/mycompany/opt/HPCCSystems/bin/testsocket</code></li><li>init.d: <code>/data/hpcc/etc/init.d</code></li><li>environment.xml: <code>/data/hpcc/etc/HPCCSystems/environment.xml</code></li></ul>`,99)])])}const m=s(i,[["render",o]]);export{h as __pageData,m as default};
